"""
Standalone patch — writes mkt-context for Isaiah 5-8 directly.
Run: python3 scripts/zc-context-isaiah-5-8-patch.py
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISA_CONTEXT = {
  "5": {
    "1": "<p>Isaiah 5 opens with the Song of the Vineyard (vv. 1-7), the most developed parable in the prophetic literature and the prototype for Jesus's parable of the wicked tenants (Matt 21:33-44; Mark 12:1-12; Luke 20:9-19). The prophet presents himself as a minstrel singing a love song (shir dodi, song of my beloved) about his beloved's vineyard. The vineyard owner is YHWH, the vineyard is Israel. The song begins seductively in the wedding-song genre before revealing itself as a lawsuit. 'My beloved had a vineyard on a rich and fertile hillside' — keren ben-shamen, literally 'on a horn of a son of oil,' = a hillside of exceptional fertility (olive-growing conditions).</p>",
    "2": "<p>'He dug it up and cleared away its stones, and planted it with the finest vines; he built a watchtower inside it and cut out a winepress in it. He expected it to produce fine grapes, but it produced only wild, sour grapes' — the vineyard owner performed every preparation a skilled vintner would make: clearing stones (an arduous, multi-year task on Judean hillsides), planting sorek (the finest Israelite grape variety, also in Gen 49:11 and Jer 2:21), building the watchtower (migdal), cutting the winepress (yeqev). Every element represents YHWH's care for Israel (the Exodus, Sinai, the land, the temple, the Davidic covenant). Yet the outcome was wild/sour grapes (be'ushim, wild/worthless grapes).</p>",
    "3": "<p>'And now, you people of Jerusalem and you citizens of Judah, judge between me and my vineyard' — the shift from third-person narrative to direct address catches the audience off guard. The listeners are asked to render a legal verdict (shifte-na, please judge) between YHWH and his vineyard. By the time they render the verdict in v. 4 (implying the vineyard deserves punishment), they have condemned themselves — the reversal is complete when v. 7 reveals the vineyard = Judah. The rhetorical trap of self-condemnation through narrative is also deployed by Nathan in his parable to David (2 Sam 12:1-7) and Jesus in his parable of the tenants.</p>",
    "4": "<p>'What more could have been done for my vineyard that I did not do? Why then, when I expected good grapes, did it produce only wild grapes?' — the divine bewilderment at covenant failure. The question is not rhetorical evasion but genuine incomprehension: YHWH provided everything (covenant, law, land, temple, prophets, deliverance from enemies) and received rebellious ingratitude. The contrast between divine expectation (waited/hoped, vayqav) and actual outcome (sour grapes) is the central tragedy. The same bewilderment appears in Jer 2:5: 'What did your ancestors find wrong in me that they strayed from me?'</p>",
    "5": "<p>'Now let me tell you what I am going to do to my vineyard: I will take away its protective hedge, and it will be consumed; I will break down its wall, and it will be trampled underfoot' — the judgment declared by the vineyard owner: removing the protective hedge (mesukato, its thorn hedge) and wall (gederato, its stone wall) that kept out animals and raiders. In ancient Israelite agriculture, a vineyard's hedge/wall was its primary protection; their removal leaves it defenseless. This is YHWH's withdrawal of covenant protection from Israel — the removal of the blessing-shield that sustained the nation. The covenant curse of Deut 28:25 ('The LORD will cause you to be defeated before your enemies') is the content of this removal.</p>",
    "6": "<p>'I will make it a ruin: it will not be pruned or cultivated, and briers and thorns will overrun it. I will command the clouds to withhold their rain from it' — the specific abandonment: no pruning (yizzamer, regular vine-pruning necessary for fruitful growth) and no cultivation (ye'ader, hoeing the soil around the vines). Left untended, the vineyard reverts to thorns and thistles — the curse of Gen 3:18 applied to the whole land. Most significantly, YHWH commands the clouds not to rain (al-hametal metar) — direct divine intervention in the rainfall cycle. In Canaanite theology, Baal provided rain; YHWH here demonstrates that he controls the rain Baal supposedly supplied, and he can withhold it.</p>",
    "7": "<p>'For the vineyard of the LORD of hosts is the house of Israel, and the men of Judah are his cherished planting. He looked for justice, but saw only oppression; for righteousness, but heard only cries of distress' — the interpretation and the famous Hebrew paronomasia: waited for mishpat (justice) but found mispach (bloodshed); for tsedaqah (righteousness) but heard tse'aqah (crying out). The wordplay is untranslatable: the sounds are almost identical but the meanings are inverted. The parable's beauty becomes a weapon — the vinegrower who invested everything in his vineyard received the precise inverse of what he sought. The 'cries of distress' (tse'aqah) echoes the cry of Sodom (Gen 18:20-21) and the cry of the oppressed slaves in Egypt (Exod 3:7).</p>",
    "8": "<p>'Woe to those who accumulate house after house and absorb field after field until no space remains' — the first of six woe-oracles (vv. 8, 11, 18, 20, 21, 22). This woe targets latifundialization: the consolidation of small landholdings into large estates owned by the wealthy elite. The Jubilee law (Lev 25:23-28) was designed precisely to prevent this: every 50 years, land reverted to its original tribal allotment to ensure distributive justice. The woe condemns those who bought out or seized the small farmers' plots. Micah 2:2 is a parallel: 'They covet fields and seize them, and houses, and take them; they oppress a man and his household.' Amos 5:11 addresses the same class.</p>",
    "9": "<p>'The LORD of hosts has sworn in my hearing: Many houses, large and fine as they are, will stand empty and desolate' — the judicial curse matching the crime: those who accumulated houses will see them empty. The punishment follows the pattern of Deut 28:30 (the covenant curse of building a house but not living in it, planting a vineyard but not enjoying its fruit). The oath formula ('sworn in my hearing') marks this as irrevocable: YHWH's sworn word cannot be recalled. The specific punishment is desolation (shamamah, desert/emptiness) — the Latin desolatio rendered the same Hebrew word used in the 'Abomination of Desolation' passages of Daniel.</p>",
    "10": "<p>'Ten acres of vineyard will produce only a single bath of wine, and a homer of seed will yield only an ephah of grain' — the specific agricultural curse. Ten acres (ten tsamidim, ten yokes — the amount one yoke of oxen could plow in a day) producing only one bath of wine (approximately 22 liters — a 10:1 ratio below normal yield). A homer of seed (a donkey-load, approximately 220 liters) yielding only an ephah (22 liters) = a 10:1 loss on seed investment. Both figures represent catastrophic agricultural failure — a 90% shortfall. This is precisely the curse of Lev 26:20 ('your land will not yield its produce') made precise and quantitative.</p>",
    "11": "<p>'Woe to those who are up at dawn chasing strong drink, who linger into the night with wine burning in their veins!' — the second woe targets the aristocratic drinking culture: rising at dawn to begin drinking (shachar, the dawn) and extending into the night. The shechar (strong drink) and yayin (wine) are the standard pair of intoxicants in the OT. The social context: the wealthy elite who feast continuously (v. 12) while the poor are ground down (3:15). Amos 6:4-6 describes the same Israelite elite 'who drink wine by the bowlful and use the finest lotions' while unconcerned with the ruin of Joseph. Ecclesiastes 10:16-17 contrasts the land cursed by feasting rulers with the land blessed by rulers who eat at the proper time.</p>",
    "12": "<p>'At their feasts there are lyre and harp, tambourine and flute and plenty of wine — but they give no thought to what the LORD has done, and they do not consider the work of his hands' — the five instruments of the feast (kinnor vavel, tof vechalil vayayin) are the full orchestra of Israelite celebration. The instruments themselves are not wrong — the same instruments appear in temple worship (Ps 150:3-5). The problem is the cognitive/theological failure: they do not consider (hibbit, look attentively at) the work of YHWH's hands (po'al yadav, what his hands have done). The feast culture produces willful amnesia about YHWH's covenant acts. Amos 6:5 ('you pluck away on your harps like David and improvise on musical instruments') similarly indicts musical self-indulgence disconnected from covenant loyalty.</p>",
    "13": "<p>'Therefore my people will go into exile for want of understanding; their distinguished men will be starving and their masses dying of thirst' — the logical consequence: exile (galah) because of lack of knowledge (beli-da'at, without knowing). The da'at (knowledge/knowing) is the covenantal knowledge of YHWH that Israel should have had (Hos 4:6: 'my people are destroyed from lack of knowledge'). The ironic inversion: the distinguished men (kavod, honorable ones) will be famished, and the masses (hamon, the multitude) will be parched with thirst — the same thirst they tried to cure with wine (v. 11) now becomes literal judgment.</p>",
    "14": "<p>'Therefore Sheol has expanded its appetite and opened its mouth without limit; Jerusalem's splendour and her crowds and her revelry and all who celebrate in her will descend into it' — Sheol personified as a voracious beast opening its gullet without limit. The verb hirchiva nefesh (has widened its throat/appetite) uses the same nefesh (throat/appetite/soul) that is expanded to receive Jerusalem's population. In ancient Israelite cosmology, Sheol was the realm of the dead below the earth — not hell in the Christian sense but the universal abode of the departed (Job 3:17-19; Ps 6:5). The specific list of Jerusalem's inhabitants going down: its kavod (glory), its hamon (multitude), its sha'on (tumult), and the exulting ones (alizah) — all the expressions of social vitality swallowed.</p>",
    "15": "<p>'Human beings are bowed down and each person humbled, and the eyes of the proud are cast down' — the Day-of-the-LORD theme from ch. 2 (2:9, 11, 17) restated: the universal humbling of human pride. This verse deliberately echoes 2:9 ('Mankind is brought low and every person humbled') indicating that the six woes of ch. 5 are the specified content of the general divine judgment announced in ch. 2. The proud gaze (einei gevohim, haughty eyes — the same physiognomy of pride as 2:11) is cast down. The 'eyes cast down' reverses the posture of the confident pride of the feast-goers of v. 12.</p>",
    "16": "<p>'But the LORD of hosts is exalted in justice, and the Holy God proves himself holy through righteousness' — the theological center of the chapter: YHWH's exaltation (yisgav, is raised up) comes through judgment (mishpat). The Holy God (ha'el haqqadosh) is sanctified/shows his holiness (veyiqqadesh) through righteousness (bitsedaqah). The divine holiness (qedushah) and righteousness (tsedaqah) are not separate attributes but mutually defining: YHWH's holiness is not an abstract metaphysical purity but an active moral righteousness that executes justice. The same connection appears in the trisagion of 6:3 and is central to Isaiah's theology of the Holy One of Israel.</p>",
    "17": "<p>'Then lambs will graze as in their own meadow, and wandering flocks will feed among the ruins of the wealthy' — the reversal: where the wealthy had their estates (the accumulated houses and fields of v. 8), sheep and goats will graze. The abandoned ruins of the latifundia aristocracy become pastureland for those who wander (gerim, sojourners/wanderers — typically the most marginal social category). The inversion is the judgment matching the crime: those who absorbed field after field receive a land that reverts to pasture. Isa 32:14 develops the same image of cities becoming open pasture after judgment.</p>",
    "18": "<p>'Woe to those who drag along iniquity with cords of deception and haul sin behind them like a cart on thick ropes' — the third woe targets deliberate, willful sin-accumulation. The imagery of hauling iniquity (avon) with cords of falsehood (chavle hashav) and sin (chata'ah) with cart ropes (ka'avot ha'agalah, like the ropes of a wagon) suggests a person who has built an entire industrial apparatus for sinning — sin is not accidental but a heavy load they transport by design. The cords of falsehood/deception (shav, vanity/falsehood) suggest that the accumulation of sin is sustained by self-deception: they have deceived themselves into thinking the sin-wagon can be managed.</p>",
    "19": "<p>'Who say: Let God hurry up, let him get on with his work so we can see it; let the purpose of the Holy One of Israel come close and happen so we can find out what it is!' — the sarcastic challenge to YHWH to prove himself: if you're going to judge us, get on with it! The phrase 'purpose of the Holy One of Israel' (atat qedosh Yisrael) uses Isaiah's distinctive divine epithet in a mocking context. The mockers are functionally atheistic not in believing YHWH doesn't exist but in treating him as powerless to act. The challenge to YHWH to perform on demand is similar to the taunt of Ps 22:8 ('let the LORD rescue him, since he delights in him') applied to Jesus on the cross.</p>",
    "20": "<p>'Woe to those who call evil good and good evil, who substitute darkness for light and light for darkness, who swap bitter for sweet and sweet for bitter!' — the fourth woe: the moral-epistemic inversion of ethical categories. The triple chiastic reversal (evil/good, darkness/light, bitter/sweet) describes a complete inversion of the moral order — not merely doing wrong while knowing it is wrong, but reconceptualizing evil as good, darkness as light. This is the deepest form of moral corruption: not a failure of will but a failure of moral perception. Paul's description of the pagan world in Rom 1:18-32 traces the progression from suppressing truth to exchanging natural for unnatural to becoming 'inventors of evil.' The Isaiah woe names what Paul describes as its endpoint.</p>",
    "21": "<p>'Woe to those who consider themselves wise and regard themselves as shrewd!' — the fifth woe: autonomous wisdom, wisdom 'in their own eyes' (chachamim be'einehem, wise in their own eyes). Prov 3:7 warns against this exact posture: 'Do not be wise in your own eyes; fear the LORD and shun evil.' The wise person in Proverbs is one whose wisdom is derived from and accountable to YHWH's instruction (Prov 1:7: 'the fear of the LORD is the beginning of wisdom'). The self-validated sage who requires no external correction from YHWH's revelation is the fool who appears wise to himself (Prov 26:12: 'Do you see a man wise in his own eyes? There is more hope for a fool than for him.').</p>",
    "22": "<p>'Woe to those who are heroes when it comes to drinking wine, champions at blending strong liquor' — the sixth woe returns to the drunkenness theme of vv. 11-12 but now with satirical heroism language. The gibborim (mighty men/warriors — the elite military class) and anshei chayil (men of valor) are the terms for Israel's warrior heroes. Here they are champions at drinking — their 'heroism' is measured in consumption capacity and skill at mixing drinks (mezeg shechar, blending strong drink). The satirical use of military honor vocabulary for drinking prowess deflates the warrior class by revealing their actual vocation.</p>",
    "23": "<p>'Who let the guilty off the hook for a bribe and strip the righteous of their legal due!' — the judicial corruption connected to the drinking culture: the drinking heroes (vv. 22) are the same leaders who corrupt the courts. 'Let the guilty off the hook' (matsdiqe rasha, who justify/acquit the wicked) and 'strip the righteous' (tsedaqat tsadiqim yisiru mehem, who remove the righteousness from the righteous) — the complete inversion of the judicial function. Prov 17:15: 'Acquitting the guilty and condemning the innocent — the LORD detests them both.' The bribe (shochad) given as payment for the corrupt verdict is the mechanism of legal inversion, the same corruption as 1:23.</p>",
    "24": "<p>'Therefore, as fire consumes stubble and dry grass collapses in flame, so their root will rot and their blossom scatter like dust; for they have rejected the instruction of the LORD of hosts and despised the word of the Holy One of Israel' — the cumulative judicial verdict on the six woe-groups. The fire-consumes-stubble imagery echoes 1:31 (the powerful becoming tinder). The specific botanical metaphor: root (shoresh) rotting and blossom/flower (perach) dispersing like dust — the entire agricultural plant, from root to flower, collapses. The root cause is stated: rejection of the torah of YHWH of hosts and contempt for the word of the Holy One of Israel — the covenant instruction that would have produced justice (v. 7) is the very thing they despised.</p>",
    "25": "<p>'For this reason the LORD's anger burned against his people; he stretched out his hand and struck them, and the mountains trembled; their bodies lay like rubbish in the middle of the streets. Despite all this, his anger has not turned away — his hand is still outstretched' — the ominous refrain 'his anger has not turned away and his hand is still outstretched' (lo-shav apo ve'od yado netuyah) appears four more times in Isaiah (9:12, 17, 21; 10:4) as the closing line of a cascading series of judgments. The stretched-out hand is the classic gesture of divine judgment (Exod 7:5: 'I will stretch out my hand against Egypt'). The mountains trembling and bodies strewn in the streets reflects the Assyrian campaigns' actual devastation of the Judean countryside.</p>",
    "26": "<p>'He raises a signal for a distant nation and whistles for it from the far ends of the earth, and look — it comes at full speed!' — YHWH as the military commander who deploys Assyria as his instrument of judgment. The 'signal' (nes, standard/flag) raised on a mountain and the 'whistle' (sharaq, hissing signal) for the distant nation (goy merachok, nation from afar) are the military deployment commands. The image of YHWH whistling for Assyria as a beekeeper whistles for bees (7:18: 'the LORD will whistle for the bee from the land of Assyria') reveals that the terrifying Assyrian army is YHWH's instrument, not an autonomous power. The swift arrival ('it comes at full speed!') immediately begins the terrifying description of vv. 27-30.</p>",
    "27": "<p>'Not one of them is tired, not one trips or falls; not one drowses or sleeps; not a belt is slack and not a sandal-strap is snapped' — the description of the Assyrian army in perfect military readiness. The negatives (no fatigue, no stumbling, no drowsiness, no loose equipment) paint a picture of a machine-like military force in peak condition. The sandal-strap not snapped is a detail of parade-ground perfection: even the soldiers' footwear is in order. Ancient military campaigning over hundreds of miles inevitably produced the fatigue and equipment failures that Isaiah's description denies. This is the supernatural vigor of YHWH's instrument of judgment — a force that does not degrade during its long march from Assyria.</p>",
    "28": "<p>'Their arrows are sharp and every bow is strung taut; their warhorses' hooves strike like flint, and their chariot wheels spin like a tornado' — the Assyrian military technology described in fearful detail: sharp arrows, taut bows, the iron-shod hooves (flint-sparking on stone roads), and the chariot wheels like a whirlwind (saphah kesufah, a storm/whirlwind). The Assyrian army was the most advanced military force of the 8th-7th century BCE, with standing armies, iron weapons, battering rams, and systematic logistics. Assyrian annals and palace reliefs confirm the technologies Isaiah describes — archers, cavalry, war chariots. Isaiah's audience would have recognized each detail with terror.</p>",
    "29": "<p>'Their battle cry is like the roar of a lion — like the roar of young lions they snarl, seize their prey, and carry it off with no one to deliver it' — the lion imagery for military power: the roar of the mature lion (layish, the old lion) and the growling of young lions (kefir). The lion seizing prey and carrying it off 'with no one to deliver it' (maphlit, no deliverer/rescuer) completes the terror picture: the prey has no advocate, no rescuer. In the ANE, the lion was the symbol of royal power and military dominance (Assyrian palace reliefs show lion hunts as royal sport, asserting the king's mastery over nature's most powerful predator). Using lion imagery for Assyria appropriates this royal symbolism for YHWH's chosen instrument.</p>",
    "30": "<p>'In that day they will roar over it like the roaring of the sea. And if someone looks out over the land — only darkness and anguish; the light is blotted out by heavy cloud' — the closing image: the noise of the approaching army like the sea's roar (qol hayyam, the voice of the sea — associated with chaos and divine power; Ps 93:3-4). Looking at the land: only darkness (choshek, dark) and anguish (tsarah, distress), the light darkened by cloud (va'or chashach ba'arafileyha, the light is dark in its clouds). The triple dark vocabulary (choshek, tsarah, chashach) closes the vineyard song's judgment with total atmospheric darkness — the opposite of the light promised to the righteous. This darkness sets up the light promised in 9:2.</p>"
  },
  "6": {
    "1": "<p>'In the year that King Uzziah died' — 740 BCE, after a 52-year reign (2 Kgs 15:2). Uzziah's death marks the end of Judah's prosperous mid-8th-century BCE period and the beginning of the Assyrian threat under Tiglath-Pileser III. Isaiah's vision is dated precisely to this hinge-year. 'I saw the Lord seated on a throne, high and exalted, and the train of his robe filled the temple' — the vision takes place in the Jerusalem temple (or a heavenly temple, or both simultaneously — the earthly temple as a copy of the heavenly, as in Exod 25:9; Heb 8:5). The train (shulav, hem/skirt) of YHWH's robe filling the temple is the overwhelming size and glory of the divine presence making even the vast space too small to contain it.</p>",
    "2": "<p>'Seraphim were standing above him, each with six wings: with two wings they covered their faces, with two they covered their feet, and with two they were flying' — the seraphim (serafim, burning/fiery ones) are unique to this vision in the OT; elsewhere cherubim (keruvim) flank the divine throne (Exod 25:18-20; Ezek 1; 10). 'Seraphim' shares the root with saraf (to burn) and with the copper/fiery serpents (nechash hanesaraph) of Num 21:6-9. The six wings serve three functions: covering the face (before the blinding divine holiness), covering the feet (a euphemism for the genitals — modesty before the holy God), and flying (active service). Revelation 4:8 transfers the sixfold wing and trisagion to the four living creatures around the heavenly throne.</p>",
    "3": "<p>'Holy, holy, holy is the LORD of hosts; the whole earth is full of his glory!' — the Trisagion (three-fold holy), the climax of the vision's auditory content. Triple repetition in Hebrew is the superlative: qadosh qadosh qadosh (holy, holy, holy) = absolutely holy, maximally holy, incomparably holy. The holiness of YHWH (his absolute separateness from all that is impure or finite) is the dominant attribute in Isaiah (the 'Holy One of Israel' epithet appears 26x). 'The whole earth is full of his glory (kavod)' — the paradox: the God too vast to fit in the temple (1 Kgs 8:27: 'the highest heavens cannot contain you') simultaneously fills the whole earth with his glory. The Trisagion became the Sanctus of the Christian Mass (from the Latin: Sanctus, Sanctus, Sanctus) and is reflected in Rev 4:8.</p>",
    "4": "<p>'At the sound of the voice that called, the door-frames shook and the entire house filled with smoke' — the theophanic responses: shaking and smoke. The door-frames shaking (yanu'u ammot hassipim, the pivots/foundations of the thresholds moved) reflects the earthquake-response to divine theophany (Ps 18:7: 'the earth trembled and quaked; the foundations of the mountains shook'; Sinai: Exod 19:18). The smoke filling the house is the theophanic cloud of YHWH's presence: the same cloud that filled the tabernacle when YHWH took up residence (Exod 40:34-35) and the temple at its dedication (1 Kgs 8:10-11). Smoke/cloud = divine glory that is perceptible but not directly visible.</p>",
    "5": "<p>'Woe is me! I am ruined! For I am a man of unclean lips, and I live among a people of unclean lips, and my eyes have seen the King, the LORD of hosts!' — Isaiah's response is not awe but existential crisis: the holiness of the divine presence exposes the prophet's impurity. The specific sin is lips (sefatayim, lips/speech) — the prophet's instrument is the mouth, and the mouth is unclean. Having pronounced six woe-oracles on others (ch. 5), Isaiah now pronounces the woe on himself: 'Woe is me!' (oy li, woe to me). The title 'the King, the LORD of hosts' (hammelech Yhwh tseva'ot) is the political/military sovereignty claim: Isaiah has seen the true king in the year another king died. The prophetic logic: seeing YHWH = facing death (Gen 16:13; Exod 33:20; Judg 6:22-23; 13:22).</p>",
    "6": "<p>'Then one of the seraphim flew to me, holding in his hand a burning coal that he had lifted from the altar with a pair of tongs' — the burning coal (ritzpah, a live coal/glowing stone) is taken from the altar (mizbeach) with tongs (melqachayim). The altar in the vision is most naturally the incense altar (the altar of burnt offering was in the outer court, not before YHWH's throne; the incense altar was in the Holy of Holies). The coal's holiness: it comes from the altar of divine presence, the place of sacrifice and atonement. The seraph's use of tongs rather than bare hands signals the coal's dangerous holiness — too holy even for the seraphim to touch directly.</p>",
    "7": "<p>'He touched my mouth with it and said: See, this has touched your lips; your guilt is removed and your sin covered over' — the purification of Isaiah's lips by the altar-coal: contact with the holy object transfers holiness and removes impurity (the same logic as the blood of the sacrifice touching the altar in Lev 17:6). 'Your guilt is removed' (sar avonecha, your iniquity has departed) and 'your sin covered over' (vachatta'techa techuppar, your sin is atoned/covered). The two terms — iniquity removed and sin atoned — represent both the objective guilt and its judicial covering. The ritual of atonement (kippur) applied directly to the prophet's person enables the prophetic mission that immediately follows.</p>",
    "8": "<p>'Then I heard the voice of the Lord saying: Whom shall I send? And who will go on our behalf? I said: Here I am! Send me' — the divine council deliberation: 'on our behalf' (lanu, for us) echoes the divine council plurals of Gen 1:26 ('Let us make mankind') and Gen 11:7 ('Come, let us go down'). Isaiah overhears the divine council's need for a messenger and volunteers: hineni shelachain (here I am, send me). The hineni (here am I) is the standard response of patriarchal availability (Abraham in Gen 22:1; Moses in Exod 3:4; Samuel in 1 Sam 3:4). Isaiah does not wait to be asked — he offers himself before he knows the content of the mission. The hardening commission (vv. 9-10) reveals that he volunteered for a difficult task without advance knowledge.</p>",
    "9": "<p>'Go and tell this people: You will keep on hearing, but never understand; you will keep on seeing, but never perceive' — the hardening commission: the paradoxical mission to proclaim a message that will not be understood. The hearing-not-understanding and seeing-not-perceiving echoes the wilderness generation (Deut 29:4: 'the LORD has not given you a mind that understands or eyes that see or ears that hear'). This verse is cited in all four Gospels as the explanation for why many of Jesus's contemporaries rejected the gospel (Matt 13:14-15 at the parable teaching; Mark 4:12; Luke 8:10; John 12:40) and twice in Acts (Acts 28:26-27 as Paul's final word to Roman Jews). Paul cites it in Rom 11:8 ('God gave them a spirit of stupor') for Israel's partial hardening until the fullness of the Gentiles.</p>",
    "10": "<p>'Deaden the heart of this people, make their ears hard of hearing, and shut their eyes — otherwise they will see with their eyes and hear with their ears and understand with their hearts, and they will turn back and be healed' — the full hardening commission with its stated purpose: to prevent turning-back-and-healing (the repentance-and-restoration that was offered in 1:18-20). The 'otherwise...they will turn back' clause reveals the paradox: YHWH is withdrawing the opportunity for repentance by making the prophetic message unintelligible. Theologically, this follows on the rejection of the offer in ch. 1: those who persistently reject the covenant word eventually lose the capacity to receive it. John 12:39-40 interprets this as divine action: 'For this reason they could not believe.'</p>",
    "11": "<p>'Then I said: How long, O Lord? He answered: Until cities are devastated and left without a single resident, until houses stand empty of people, and the land is laid waste completely' — the 'How long' (ad-matay, until when?) question is the lament question of the psalms (Ps 13:1; 79:5; 89:46). The answer is devastating: the hardening continues until complete desolation. 'Cities devastated' (charu ha'arim) and 'houses without people' (battim me'ein adam) and 'land laid utterly waste' (ha'adamah tishav shamamah) — the three spheres of inhabited life (city, house, land) all emptied. The answer is not 'until they repent' but 'until devastation is complete' — the judgment will run its full course.</p>",
    "12": "<p>'And the LORD has sent people far into exile, and the desolate places are widespread across the land' — the exile (verichaq YHWH et-ha'adam, the LORD has sent humanity far away) is the ultimate covenant curse of Deut 28:63-64 ('the LORD will uproot you from the land... and scatter you among all nations'). The geographical reach ('far away') mirrors the distant nation summoned in 5:26. The 'desolate places widespread' (veravah ha'azuvah, the abandonment is great) — the landscape of the Assyrian aftermath is one of abandoned and depopulated territory, the physical mark of judgment. The exile Isaiah predicts was first fulfilled by the Assyrian deportation of the north (722 BCE) and then by the Babylonian exile (587-586 BCE).</p>",
    "13": "<p>'And even if a tenth should survive, it too will be burned — like a terebinth or an oak that still has its stump after the tree has been cut down. Yet the holy seed will be the stump' — the stump theology: even the remnant (a tenth) will be burned, like a tree cut down. But the stump remains. The terebinth/oak comparison works on two levels: in Israelite ecology, a cut-down oak or terebinth retains its root system and sends up new shoots from the stump; the stump is the guarantee of future growth. 'The holy seed (zera qodesh) will be the stump (matzevet)' — the holy seed is the remnant from which restoration comes. Isaiah 11:1 develops this: 'A shoot will come up from the stump of Jesse; from his roots a Branch will bear fruit.' The stump theology is the basis for all subsequent restoration prophecy.</p>"
  },
  "7": {
    "1": "<p>Isaiah 7 is set in the Syro-Ephraimite Crisis of 735-732 BCE: Rezin king of Syria (Aram/Damascus) and Pekah king of Israel (the Northern Kingdom/Ephraim) formed a coalition against Assyria and attempted to force Judah to join. When Ahaz refused, they attacked Jerusalem to replace him with 'the son of Tabeal' (a pro-coalition puppet king, v. 6). Tiglath-Pileser III's annals confirm the campaign and the coalition. Ahaz's response was to appeal to Assyria for military aid (2 Kgs 16:7-8: 'I am your servant and vassal — come up and save me'), which Isaiah opposed as a faithless substitute for trust in YHWH.</p>",
    "2": "<p>'When the house of David was told that Syria had allied with Ephraim, the heart of Ahaz and the hearts of his people shook like the trees of the forest trembling in the wind' — 'the heart of Ahaz' (lev Achaz) and 'the hearts of his people' (lev amo) shaking like forest trees in the wind: the simile is of trees in full canopy caught by the wind — visible, external agitation of something that should be stable. The house of David is threatened by a military coalition that intends to dismantle the Davidic throne. The fear of the Davidic dynasty is the specific anxiety Isaiah addresses: the covenant with David (2 Sam 7) promises the dynasty's perpetuity, and YHWH's faithfulness to that covenant is the basis for the faith-call of v. 9.</p>",
    "3": "<p>'Then the LORD said to Isaiah, Go out now to meet Ahaz, you and your son Shear-jashub, at the end of the conduit of the upper pool, on the road to the Fuller's Field' — Shear-jashub (she'ar yashub, 'a remnant will return') is Isaiah's eldest son, whose name is a walking prophecy. The conduit of the upper pool (techalat ha'berekhah ha'elyonah) is the same location where Sennacherib's Rabshakeh later stood to threaten Jerusalem (2 Kgs 18:17; Isa 36:2) — the geographically significant water supply point outside the city walls. The Fuller's Field (sade kavves, the washing field where cloth was bleached) was a well-known landmark. The precision of the meeting place suggests historical authenticity.</p>",
    "4": "<p>'Say to him: Be careful, stay calm, and do not be afraid; do not lose heart because of these two smoldering stubs of firewood — the fierce anger of Rezin and Syria and of the son of Remaliah' — 'smoldering stubs of firewood' (zanboth hasheqedim ha'asherot ha'eleh, the tails of these two smoking firebrands) — Rezin and Pekah as nearly-spent firebrands, still smoking but almost burned out. YHWH's perspective on the threat that has terrified Ahaz is that the attackers are nearly finished. The consistently dismissive reference to Pekah as 'the son of Remaliah' (never by name in chs. 7-8) is a prophetic insult — denying him the dignity of personal recognition. The three commands (be careful/guard yourself, stay calm, don't be afraid) structure the call to covenant faith.</p>",
    "5": "<p>'Because Syria, Ephraim, and the son of Remaliah have devised evil against you, saying' — the reason for the oracle: the three-party alliance (Aram, Ephraim, Remaliah's son) has plotted (ya'ats ra'ah alecha, counseled evil against you). The evil counsel against Judah is about to be declared in v. 6, and YHWH's counter-declaration follows in v. 7. The structure is a formal divine countering of human counsel: the nations' plan (vv. 5-6) vs. YHWH's word (v. 7). In Isa 8:10, the same pattern: 'Devise your plans — they will come to nothing; speak your word — it will not stand, for God is with us.'</p>",
    "6": "<p>'Let us march against Judah, terrify it, breach its walls, and set the son of Tabeal as king over it' — the specific war aim: to replace Ahaz with 'the son of Tabeal' (ben-Tave'al, possibly a Syrian or Transjordanian name — someone acceptable to the coalition). The four-fold plan: march against (na'aleh veYehudah, go up against Judah), terrify (venequtsennah, cause it to quake), breach (venivke'ah, make a breach), and install a puppet king. The son of Tabeal would have made Judah a client state of the Syro-Israelite coalition rather than an independent Davidic monarchy. The Davidic covenant (2 Sam 7) guaranteed the dynasty; a successful coup would have abrogated it.</p>",
    "7": "<p>'Thus says the Lord GOD: It will not happen; it will not come to pass' — the divine counter-declaration: lo taqum velo tihyeh (it will not stand and it will not be). The double negation is absolute. YHWH's word (ne'um Adonay Yhwh, the utterance of the Lord GOD) is the sovereign counter to the nations' counsel (8:10: 'Devise your plans — they will come to nothing; speak your word — it will not stand'). The brevity and decisiveness of the divine word against the elaborate four-stage plan of v. 6 is intentional: YHWH's one word cancels the entire coalition strategy.</p>",
    "8": "<p>'For the head of Syria is Damascus, and the head of Damascus is Rezin; and within sixty-five years Ephraim will be shattered so that it is no longer a people' — the 65-year countdown for Ephraim's complete dissolution as a people. Samaria/Ephraim fell to Assyria in 722 BCE (18 years after 740 BCE), but the final dissolution through Esarhaddon's resettlement of foreign peoples in 672 BCE (about 65 years from ~737 BCE) produced the ethnically mixed Samaritan population. The specific 65-year figure distinguishes between the initial defeat (722 BCE) and the complete national dissolution (672 BCE). The point is not the precise calculation but the prophetic confidence: the threatening power will itself be annihilated.</p>",
    "9": "<p>'The head of Ephraim is Samaria, and the head of Samaria is Remaliah's son. If you do not stand firm in faith, you will not stand at all' — the famous faith-formula: im lo ta'aminu ki lo te'amenu. The wordplay is on the root aman (to be firm, trustworthy, to have faith): 'If you do not stand firm in faith (ta'aminu, you believe/trust/are firm), you will not stand at all (te'amenu, you will be made firm).' The NIVSB glosses it: 'If you do not stand firm in faith, you will not stand at all.' Active faith in YHWH's word = the basis for political stability. Passive/anxious diplomacy that goes to Assyria instead of YHWH = the path to instability. The formula encapsulates Isaiah's entire political theology.</p>",
    "10": "<p>'Again the LORD spoke to Ahaz, saying' — the second divine word following v. 7-9: YHWH continues the dialogue with Ahaz, now adding a specific sign offer. The address to Ahaz directly (not through Isaiah) personalizes the divine invitation. The structure of the encounter: YHWH offers faith (vv. 3-9), then offers a sign to confirm the promise (vv. 10-17), which Ahaz hypocritically refuses (v. 12), and the sign is given anyway (v. 14 — the Immanuel sign).</p>",
    "11": "<p>'Ask a sign from the LORD your God; let it be as deep as Sheol or as high as the heavens above' — the remarkably generous sign offer: any sign, from the deepest depths to the highest heights. 'The LORD your God' (Yhwh Elohecha) — YHWH invites a personal relationship ('your God') even while Ahaz is refusing to trust him. The breadth of the offer (Sheol to heaven) means no sign is too extraordinary to request — YHWH's credibility is fully on the table. The offer to perform any sign is the divine vulnerability of covenant relationship: YHWH is willing to demonstrate his trustworthiness to a king who is about to reject it.</p>",
    "12": "<p>'But Ahaz said: I will not ask, and I will not put the LORD to the test' — the pious-sounding refusal: Ahaz quotes Deut 6:16 ('Do not put the LORD your God to the test') as a religious reason for not accepting the sign. But the refusal is not piety — it is the rejection of YHWH's personal invitation to ask. YHWH himself offered the sign; to refuse it is to reject YHWH's initiative, not to honor it. Ahaz has already decided to appeal to Assyria (2 Kgs 16:7-8) and doesn't want a YHWH-sign that would obligate him to trust YHWH instead. The irony is devastating: Ahaz uses the language of faithfulness to perform an act of faithlessness.</p>",
    "13": "<p>'Then Isaiah said: Hear now, O house of David! Is it too small a thing for you to weary men? Must you weary my God as well?' — Isaiah's frustration breaks through: Ahaz's refusal has 'wearied' (halot, exhausted/worn out) not just human patience but YHWH himself. The address shifts from Ahaz personally to 'the house of David' — the dynasty is implicated in Ahaz's faithlessness. 'Must you weary my God as well?' — 'my God' (Elohai), not 'your God' (as in v. 11): Isaiah distinguishes himself from Ahaz's unfaith by claiming personal relationship with YHWH while Ahaz's relationship is effectively abandoned.</p>",
    "14": "<p>'Therefore the Lord himself will give you a sign: Behold, the young woman shall conceive and bear a son, and she shall call his name Immanuel' — the most debated verse in the OT. The Hebrew 'almah (young woman of marriageable age) is not the technical term for virgin (betulah) but refers to a young woman of the right age to bear children. The LXX translated 'almah as parthenos (virgin), which Matthew 1:23 cites for the virginal conception of Jesus. In its immediate historical context, the sign addresses the Syro-Ephraimite threat: before the Immanuel child can distinguish good from evil, the threatening kings will be gone (v. 16). In its canonical, NT-reception context, the 'God with us' child is Jesus. The name Immanuel (immanu El, God-with-us) is the theological center.</p>",
    "15": "<p>'He shall eat curds and honey until he knows how to refuse evil and choose good' — curds and honey (chem'ah udevash, butter-and-honey) are the food of a desolated but surviving land: when agriculture collapses and vineyards become briers (v. 23-25), the pastoral survivor lives on dairy (from cattle) and wild honey. The diet of subsistence/survival rather than agricultural abundance signals the difficult period through which the sign-child will live. 'Until he knows how to refuse evil and choose good' — this is the threshold of moral consciousness, approximately 3-5 years of age in ancient contexts. The time-marker calibrates the sign: within a few years of the child's birth, the threat will be over.</p>",
    "16": "<p>'For before the child knows how to refuse evil and choose good, the land whose two kings you dread will be forsaken' — the specific promise to Ahaz: within the child's early years, Damascus and Samaria (the two lands whose two kings threaten Judah) will be abandoned by their current rulers. The historical fulfillment: Tiglath-Pileser III deported Damascus's population and killed Rezin in 732 BCE; Pekah of Samaria was assassinated by Hoshea in 732 BCE (2 Kgs 15:30). The sign worked precisely as predicted — both threatening kingdoms were eliminated within a few years. The 'child's early years' timeframe was fulfilled.</p>",
    "17": "<p>'The LORD will bring on you, your people, and your father's house such days as have not come since the day Ephraim departed from Judah — the king of Assyria' — the ominous rider on the promise: YHWH will also bring Assyria on Judah. The reference to 'the day Ephraim departed from Judah' dates the standard of calamity to the kingdom division under Rehoboam (931 BCE). Judah's days under Assyria will be worse than anything since the kingdom split. This is the theological irony: by seeking Assyria's protection (2 Kgs 16:7-8), Ahaz is calling for the very power that will devastate Judah. The solution becomes the problem.</p>",
    "18": "<p>'In that day the LORD will whistle for the fly from the farthest reaches of the rivers of Egypt, and for the bee from the land of Assyria' — the fly/Egypt and bee/Assyria metaphor: the two great superpowers summoned as insects by YHWH's whistle. Egypt is a fly (zavuv, the swarm fly that infests the Nile Delta region), Assyria is a bee (devorah, the honey-producing but stinging bee). Both are controlled by YHWH's whistle (yishreq, he will hiss/whistle — the beekeeper's signal to the swarm). The bee's stinging aspect makes it the more dangerous of the two. The image renders the fearsome military powers as insects at YHWH's command.</p>",
    "19": "<p>'They will all come and settle in the steep ravines, in the crevices of the rocks, on all the thornbushes, and on all the pastures' — the 'fly' and 'bee' armies settling throughout Judah's landscape: ravines, rock crevices, thornbushes, pastures. The swarming metaphor continues: the invading forces occupying every ecological niche of the land as completely as insects colonize a landscape. The four settling places (ravines, rocks, thornbushes, pastures) cover the full topographic range of Judah — highland to lowland, cultivated to wild. The invasion is complete and pervasive.</p>",
    "20": "<p>'In that day the Lord will shave with a hired razor — with those from beyond the Euphrates, with the king of Assyria — shaving the head, the hair of the legs, and the beard as well' — the humiliation metaphor of the razor: YHWH hiring Assyria as a razor to shave Judah. In the ancient Near East, shaving the head and beard was the mark of mourning, defeat, and subjugation (2 Sam 10:4: Hanun shaved David's envoys as an insult). The hired razor (ta'ar hasekir) is Assyria, hired by YHWH (not by Ahaz, reversing Ahaz's self-conception in 2 Kgs 16:7-8: 'I am your servant'). Shaving the entire body (head, legs, beard) = complete subjugation and humiliation of the nation.</p>",
    "21": "<p>'In that day a man will keep alive one young cow and two sheep' — the agricultural reduction: the abundance of Israelite farming (flocks, herds, vineyards) reduced to one cow and two sheep per household. This is survival-level animal husbandry — enough for milk but not for commerce or sacrifice. The reduction from prosperity to subsistence is the economic face of the Assyrian devastation. The Assyrian military practice of stripping conquered territories of agricultural capacity (deporting skilled farmers, confiscating livestock) produced exactly this subsistence reality.</p>",
    "22": "<p>'And because of the abundance of milk they produce, he will eat curds; curds and honey will be the diet of everyone left in the land' — the ironic silver lining: even in devastation, curds and honey (the diet of vv. 15 and 14:30). With so few people and so many cattle for the small surviving population, there is enough milk to produce curds for all. Honey from wild bees fills the remainder of the diet. This is sustenance in the ruins of agricultural civilization — the same foods but in a context of desolation rather than abundance.</p>",
    "23": "<p>'In that day every place that once held a thousand vines, worth a thousand silver pieces, will become briers and thorns' — the precise economic loss: the thousand-vine vineyard (representing significant capital investment — a thousand silver pieces) reverts to thorns and briers (shamir vashayit, the same thorn-and-brier pair that recurs in Isaiah as the image of judgment on the land). Viticulture (winemaking) was Judah's premium agricultural export and the basis of its economic prosperity. The destruction of the vineyards (also predicted in 5:5-6) represents the collapse of the agricultural economy.</p>",
    "24": "<p>'Men will come there with bow and arrows, for all the land will be briers and thorns' — the reversal: the cultivated vineyards become hunting grounds. Men come not to harvest grapes but to hunt game in the wild land. The bow and arrows (bechetz uvaqeshet) are hunting tools in a landscape that has reverted from agriculture to wilderness. The detail reveals the population collapse: the vineyards' owners are gone (deported, killed), the cultivation is abandoned, and wildlife has reclaimed the land.</p>",
    "25": "<p>'But all the hills once cultivated with the hoe — no one will go there for fear of briers and thorns; they will be given over to cattle and trampled by sheep' — the complete reversal of Judean agriculture: the carefully terraced and hoed hillsides (a vast investment of labor over centuries) are given over to cattle and sheep for trampling (mirsas bakar ulishalach tson, a trampling place for cattle and a let-loose place for sheep). The hillside vineyards and grain terraces that characterized the Judean highlands will revert to pasture. Archaeological evidence confirms the depopulation of the Judean Shephelah after the 701 BCE Assyrian campaign.</p>"
  },
  "8": {
    "1": "<p>'Then the LORD said to me: Take a large writing tablet and write on it in common script: Maher-shalal-hash-baz' — the third prophetic sign after the Immanuel sign (7:14) and Shear-jashub (7:3). 'Maher-shalal-hash-baz' (meher shalal chash baz, 'speed the spoil, hasten the plunder') is the longest personal name in the OT and an announcement of imminent Assyrian conquest. The 'large writing tablet' (gillyon gadol, large tablet) inscribed in 'common script' (cheret enosh, the writing of ordinary people/common inscription) ensures public accessibility — the prophecy is written where all can read it. The public nature is the authentication: when the event happens, all can verify the prior prediction.</p>",
    "2": "<p>'And I called in reliable witnesses, Uriah the priest and Zechariah son of Jeberechiah' — the legal authentication of the prophetic word: two witnesses (the minimum required by Deut 19:15 for legal establishment of a matter). Uriah the priest appears in 2 Kgs 16:10-16 as the priest who built an Assyrian altar for Ahaz — a collaborator with the king's pro-Assyrian policy. Zechariah son of Jeberechiah is otherwise unknown. The witnesses are from the establishment — not Isaiah's disciples but public figures who will be around to testify when the prophecy is fulfilled.</p>",
    "3": "<p>'Then I went to the prophetess, and she conceived and bore a son. The LORD said to me: Name him Maher-shalal-hash-baz' — 'the prophetess' (haneviah, the female prophet) is almost certainly Isaiah's wife rather than a title for an unrelated female prophet. The birth is not miraculous (unlike the Immanuel sign of 7:14) but a normal conception and birth. The child named with the prophetic name is the third sign-child: Shear-jashub (7:3: remnant will return), Immanuel (7:14: God with us), and Maher-shalal-hash-baz (speed the plunder). Isaiah's family becomes a walking prophetic message.</p>",
    "4": "<p>'For before the child knows how to say My father or My mother, the wealth of Damascus and the plunder of Samaria will be carried off before the king of Assyria' — the timing sign: before the infant can speak 'abi' (my father) or 'immi' (my mother) — the first words of a nursing child. This is approximately one year of age. Within that timeframe, Damascus's wealth and Samaria's spoil will be carried to Assyria. Historical fulfillment: Tiglath-Pileser III captured Damascus and deported its population in 732 BCE, and the northern kingdom's capital Samaria fell in 722 BCE. The name 'speed the plunder, hasten the spoil' is the event compressed into a child's name.</p>",
    "5": "<p>'The LORD spoke to me again, saying' — the brief narrative break (v. 5) before the 'waters of Shiloah' oracle marks the transition from the sign-child narrative (vv. 1-4) to the interpretive oracle (vv. 6-8). The 'again' suggests continued divine communication — Isaiah is the ongoing recipient of prophetic word during this period of Assyrian threat. The oracle that follows (vv. 6-8) interprets the present political situation in terms of water: Israel chose the wrong water source.</p>",
    "6": "<p>'Because this people has rejected the waters of Shiloah that flow gently, and rejoice over Rezin and the son of Remaliah' — the waters of Shiloah (mei hashiloach, the waters of Siloam) flowed gently (haholekhim le'at, walking slowly) through Jerusalem as a gentle, reliable supply. In John 9:7, 11, the Pool of Siloam is where Jesus sends the blind man to wash — 'Siloam' meaning 'sent.' The gentle waters of Shiloah = YHWH's quiet, covenant provision for Jerusalem. This people rejected the gentle water and 'rejoiced over Rezin and Remaliah's son' — the coalition that threatened Jerusalem. The rejection of divine provision for confidence in human political alliances is the core accusation.</p>",
    "7": "<p>'Therefore, behold, the Lord is bringing up against them the mighty floodwaters of the River — the king of Assyria and all his power. It will rise over all its channels and overflow all its banks' — the contrasting waters: the gentle Shiloah vs. the Euphrates (hanahur haatsum veharav, the mighty and great river). The Euphrates in full flood overflows its banks (all its channels — kulnahalav, all its wadis). The geographic logic: rejecting the gentle local water in favor of dependence on the great river power (Assyria = the Euphrates River civilization) will result in being flooded by that great river. The river-flood metaphor (Assyrian armies as rising waters) is developed in Jer 46:7-8 and Hab 3:8.</p>",
    "8": "<p>'Sweeping through Judah, overflowing as it goes, reaching even to the neck; and with its outspread wings it will fill the entire breadth of your land, O Immanuel' — the flood metaphor extends: the Assyrian flood sweeps through Judah reaching 'to the neck' (ad-tsavar) — nearly submerging but not quite. The neck-level flood means Jerusalem is barely above water: surrounded, threatened, almost overwhelmed but not destroyed. Sennacherib's 701 BCE campaign literally did this — 46 cities destroyed, Hezekiah 'like a bird in a cage' (Taylor Prism) but Jerusalem not taken. 'O Immanuel' — the land addressed by the name of 7:14: God is with us in the flood. The Immanuel name is the guarantee of non-destruction even in the midst of near-submersion.</p>",
    "9": "<p>'Band yourselves together, O peoples, and you will be broken in pieces; give ear, all you distant lands: arm yourselves and you will be broken in pieces; arm yourselves and you will be broken in pieces!' — the defiant challenge to the nations: three-fold 'you will be broken to pieces' (ro'u, be shattered). The rhetorical triple intensifies: 'band together' (ro'u, be hostile), 'arm yourselves' (hitallu, arm/gird yourselves), 'arm yourselves again' — each attempt at hostile mobilization is met with the same counter: shattering. The confidence here is based on Immanuel (v. 8 and v. 10: 'God is with us'): the nations' plans are futile when the God of Zion is present.</p>",
    "10": "<p>'Devise your plans — they will come to nothing; speak your word — it will not stand, for God is with us' — 'God is with us' (ki immanu El) unpacks the name Immanuel (immanu El, God-with-us, 7:14). The nations' plans (otsu etsah, take counsel) and their word (dabru davar, speak the word) will both fail: it will not stand (velo yaqum, it will not arise/stand). The same formula as 7:7 (lo taqum velo tihyeh, it will not stand and will not be). The theological ground for political confidence: Immanuel — the divine presence with his people — makes human coalition-building ultimately futile against Jerusalem.</p>",
    "11": "<p>'For the LORD spoke to me with his strong hand upon me, and warned me not to walk in the way of this people, saying' — 'with his strong hand upon me' (be'chezqat hayad, with the strength of the hand) is the language of prophetic compulsion: the divine hand that came upon Ezekiel (Ezek 1:3; 3:14, 22; 8:1; 37:1; 40:1) and Elijah (1 Kgs 18:46). Isaiah is being warned against a specific path: the way of 'this people' (ha'am hazeh, the same dismissive phrase as 6:9-10). The prophet is being called out of the crowd — marked as distinct from the prevailing political and theological consensus.</p>",
    "12": "<p>'Do not call a conspiracy everything this people calls a conspiracy; do not fear what they fear, and do not dread it' — the prophetic counter-culture: Isaiah is not to adopt the fear-vocabulary of the populace. 'Conspiracy' (qesher, a plot/conspiracy) — the people see political conspiracy everywhere; Isaiah is not to adopt their conspiratorial framework. The specific fears may be the Syro-Ephraimite threat or the anticipated Assyrian response to Judah's position. The prophetic calling involves a different epistemology: seeing events through YHWH's perspective rather than through the anxiety of political calculation.</p>",
    "13": "<p>'But the LORD of hosts — him you shall regard as holy; let him be your fear, and let him be your dread' — the substitution of fears: YHWH replaces the political/military fears of the populace. 'Regard as holy' (taqidishu, you will sanctify/set apart) — acknowledging YHWH's holiness (as in the trisagion of 6:3) is the cognitive act that relocates fear. 'Your fear' (morakchem, your reverence/fear) and 'your dread' (umor'akchem, what you dread) — the emotional responses appropriate to danger are redirected from the Assyrian army to YHWH. Prov 1:7 and the wisdom tradition: the fear of YHWH is the beginning of wisdom; all other fears are derivative and manageable.</p>",
    "14": "<p>'He will be a sanctuary, but also a stone that people stumble over, a rock that makes them fall — a trap and a snare for both houses of Israel and for the inhabitants of Jerusalem' — the two effects of YHWH's holiness: sanctuary (miqdash, holy place/refuge) for those who fear him, stumbling-stone (even negef, stone of stumbling) and rock of offense (tsur michshol, rock that causes falling) for both houses of Israel. The stone metaphor applied to YHWH himself: Paul in Rom 9:33 combines this verse with Ps 118:22 (the cornerstone) to explain Israel's rejection of the gospel: 'a stone that causes people to stumble and a rock that makes them fall.' 1 Pet 2:8 applies the same combination to Christ. The stone of YHWH/Christ is simultaneously foundation and stumbling-block.</p>",
    "15": "<p>'And many among them will stumble; they will fall and be broken; they will be snared and captured' — the three verbs of stumbling/disaster for those who reject YHWH's lordship: kashlu (they will stumble), venapelu venishbaru (they will fall and be broken/shattered), venoqushu venilkadu (they will be snared and captured). The progression from stumbling to capture is the escalating catastrophe that follows YHWH being a stumbling-stone rather than a sanctuary. The snare/trap imagery (moqesh vepach) is the hunter's language — YHWH as the trapper of those who reject him is also in Ps 91:3 (YHWH delivering from the fowler's trap) applied inversely.</p>",
    "16": "<p>'Bind up the testimony; seal the teaching among my disciples' — the formation of Isaiah's prophetic circle: the testimony (te'udah, the witnessed/attested word) is bound (tsror, tie/wrap up) and the teaching/torah (torah, instruction) is sealed (chatom, sealed with a seal) among Isaiah's disciples (limmudai, my learned ones). The sealing is for preservation until the prophecy is fulfilled — a future generation will be the audience for the message rejected in the present. This verse may explain the editorial history of Isaiah: a school of disciples preserved and expanded the master's prophecies. The same concept appears in 30:8 ('write it on a tablet and inscribe it in a book so that it may be for the time to come as a witness forever').</p>",
    "17": "<p>'I will wait for the LORD, who is hiding his face from the house of Jacob, and I will hope in him' — the hiding of the divine face (hamesater panav, the one who hides his face) during the Assyrian period is the prophetic equivalent of the lament psalms (Ps 13:1: 'How long will you hide your face from me?'; 27:9: 'Do not hide your face from me'). Isaiah's personal posture of waiting and hoping (veyichalti lo, I will hope/wait for him) while YHWH hides his face is the prophetic spirituality of the interval between word and fulfillment. The waiting prophet becomes the model for the believing community that waits for YHWH's hidden face to turn again.</p>",
    "18": "<p>'Here am I, and the children the LORD has given me. We are signs and wonders in Israel from the LORD of hosts who dwells on Mount Zion' — Isaiah and his sign-children (Shear-jashub, Maher-shalal-hash-baz, and implicitly Immanuel) constitute a living symbolic system: signs (otot) and wonders (moftim) from YHWH. Heb 2:13 cites this verse (along with Ps 22:22) to show Jesus as the one who sanctifies his brothers, sharing in their humanity: 'Here am I, and the children God has given me.' The application: Jesus and his people are the new prophetic family — signs and wonders from YHWH. 'Who dwells on Mount Zion' grounds the prophetic authority in YHWH's specific location: the Jerusalem temple.</p>",
    "19": "<p>'When people say to you: Consult the mediums and the spiritists who whisper and mutter — should not a people consult their God? Why should the living seek guidance from the dead?' — the anti-necromancy polemic: in the crisis of the Assyrian threat, consulting mediums (ha'ovot, the spirits of the dead conjured by mediums — from 'ov, a ghost) and spiritists (hayide'onim, those who know/summon the dead) is offered as a substitute for YHWH's word. Necromancy was common in the ANE (Mesopotamian and Egyptian necromantic practices are well attested) and explicitly prohibited in Deut 18:10-11 and Lev 19:31; 20:6. 'Why should the living seek guidance from the dead?' (lamedaber el-hameth, to speak to the dead) — the rhetorical logic is stark: dead spirits are not sources of living guidance.</p>",
    "20": "<p>'To the teaching and to the testimony! If anyone does not speak according to this word, it is because there is no light in them' — the canonical criterion: Torah and testimony (letorah velite'udah, to the instruction and to the witnessed word) are the standard by which all other guidance is tested. The mediums and spiritists of v. 19 fail this test. 'No light in them' (sheyn lo shachar, there is no dawn in them) — 'shachar' (dawn/morning light) is not just physical light but enlightenment, understanding, divine communication. The medium who does not align with Torah has no divine light — their words come from a different source entirely.</p>",
    "21": "<p>'They will roam through the land, hard-pressed and famished; and when hunger seizes them, they will be enraged and will curse their king and their God, and look upward' — the consequence for those who reject Torah and pursue mediums: wandering in hunger and want. 'Curse their king and their God' (veqillel bemalko uvelohav) — in the extremity of suffering, the unfaithful curse YHWH and the king rather than repenting. The looking upward (venabbet la'maalah) from v. 21 is paired with the looking earthward of v. 22 — neither direction offers relief, because the rejection of YHWH's word has closed off both the divine source above and the earthly world below.</p>",
    "22": "<p>'And then look to the earth and see nothing but distress and darkness, the gloom of anguish, and they will be thrust into thick darkness' — the closing darkness image echoes 5:30 and prepares for the great light of 9:2 ('the people walking in darkness have seen a great light'). 'Distress and darkness' (tsarah vechoshekh), 'gloom of anguish' (me'uf mutsaq), and 'thick darkness' (afelah) — four synonyms for darkness/despair pile up. The darkness is both literal (the crisis of Assyrian invasion) and spiritual (the consequence of rejecting YHWH's light). The next verse (9:1) begins: 'But there will be no more gloom for those who were in distress' — the contrast pivot from darkness (chs. 7-8) to light (9:1-7) is one of Isaiah's greatest literary and theological movements.</p>"
  }
}

def main():
    c = load_comm('mkt-context', 'isaiah')
    merge_comm(c, ISA_CONTEXT)
    save_comm('mkt-context', 'isaiah', c)
    total_v = sum(len(vv) for vv in c.values())
    print(f'Isaiah context: {len(c)} chapters, {total_v} verses')

if __name__ == '__main__':
    main()
